import { useEffect, useState } from "react";
import { Footer } from "./Footer";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import pattern from "../slike/pattern4.jpg";


export function GostiRecepcionar() {
    const [gosti, setGosti] = useState([]);
    const [izabraniGost, setIzabraniGost] = useState(null);
    const [showModal, setShowModal] = useState(false);
    const [search, setSearch] = useState("");

    // Učitavanje gostiju iz backenda
    useEffect(() => {
        fetch("http://localhost:8080/guests/all")
            .then((res) => res.json())
            .then((data) => {
                if (data && data.data && data.data.values) {
                    setGosti(data.data.values);
                }
            })
            .catch((err) => console.error("Greška pri učitavanju gostiju:", err));
    }, []);

    // Brisanje gosta
    const handleDelete = async (idGost) => {
        if (window.confirm("Da li ste sigurni da želite da obrišete ovog gosta?")) {
            await fetch("http://localhost:8080/guests/delete", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(idGost),
            });
            setGosti(gosti.filter((g) => g.idGost !== idGost));
        }
    };

    // Otvaranje modala za dodavanje ili izmenu
    const handleEdit = (gost = null) => {
        setIzabraniGost(gost ? { ...gost } : { ime: "", prezime: "", email: "", telefon: "", adresa: "", datumRodjenja: "", grad: { idGrad: 1 } });
        setShowModal(true);
    };
    // Provera email-a
    const emailPostoji = gosti.some(
        (g) => g.email.toLowerCase() === izabraniGost.email.toLowerCase() 
               && g.idGost !== izabraniGost.idGost
    );

    if (emailPostoji) {
        alert("Ovaj email već postoji. Unesite drugi email.");
        return; // prekida dalje čuvanje
    }

    // Čuvanje novog ili izmenjenog gosta
    const handleSave = async () => {
        const url = izabraniGost.idGost
            ? "http://localhost:8080/guests/update"
            : "http://localhost:8080/guests/add";

        await fetch(url, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(izabraniGost),
        });

        // Refresh tabele
        const updatedGuests = izabraniGost.idGost
            ? gosti.map((g) => (g.idGost === izabraniGost.idGost ? izabraniGost : g))
            : [...gosti, izabraniGost];

        setGosti(updatedGuests);
        setShowModal(false);
    };

    // Filtriranje gostiju po search inputu
    const filteredGosti = gosti.filter(
        (g) =>
            g.ime.toLowerCase().includes(search.toLowerCase()) ||
            g.prezime.toLowerCase().includes(search.toLowerCase()) ||
            g.email.toLowerCase().includes(search.toLowerCase())
    );

    return (

        <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", justifyContent: "space-between" }}>
            <NavBarRecepcionar />
            <div
                style={{
                    backgroundImage: `url(${pattern})`,
                    backgroundSize: "cover",
                    backgroundPosition: "center",
                    minHeight: "100vh",
                    padding: "40px",
                }}
            >
                <h2
                    style={{
                        textAlign: "center",
                        color: "white",
                        backgroundColor: "rgba(226, 108, 255, 0.7)",
                        padding: "15px 30px",
                        borderRadius: "10px",
                        display: "inline-block",
                        marginBottom: "30px",
                    }}
                >
                    Lista gostiju
                </h2>

                <div style={{ marginBottom: "20px", textAlign: "center" }}>
                    <input
                        type="text"
                        placeholder="Pretraži goste..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        style={{ padding: "10px", width: "300px", borderRadius: "5px", border: "1px solid #ccc" }}
                    />
                    <button
                        onClick={() => handleEdit(null)}
                        style={{
                            marginLeft: "10px",
                            padding: "10px 15px",
                            borderRadius: "5px",
                            backgroundColor: "#9d3dd5ff",
                            color: "white",
                            border: "none",
                            cursor: "pointer",
                        }}
                    >
                        Dodaj gosta
                    </button>
                </div>

                <div style={{ display: "flex", flexWrap: "wrap", gap: "20px", justifyContent: "center" }}>
                    {filteredGosti.map((gost) => (
                        <div
                            key={gost.idGost}
                            style={{
                                backgroundColor: "rgba(255,255,255,0.9)",
                                width: "280px",
                                borderRadius: "10px",
                                padding: "15px",
                                textAlign: "left",
                                boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
                            }}
                        >
                            <p>
                                <strong>Ime:</strong> {gost.ime} {gost.prezime}
                            </p>
                            <p>
                                <strong>Email:</strong> {gost.email}
                            </p>
                            <p>
                                <strong>Telefon:</strong> {gost.telefon}
                            </p>
                            <p>
                                <strong>Adresa:</strong> {gost.adresa}
                            </p>
                            <p>
                                <strong>Grad:</strong> {gost.grad ? gost.grad.naziv : ""}
                            </p>
                            <p>
                                <strong>Datum rođenja:</strong> {gost.datumRodjenja}
                            </p>

                            <div style={{ display: "flex", justifyContent: "flex-end", gap: "10px", marginTop: "10px" }}>
                                <button
                                    onClick={() => handleEdit(gost)}
                                    style={{ backgroundColor: "#e3dd61ff", color: "black", border: "none", padding: "5px 10px", borderRadius: "5px", cursor: "pointer" }}
                                >
                                    ✏️ Izmeni
                                </button>
                                <button
                                    onClick={() => handleDelete(gost.idGost)}
                                    style={{ backgroundColor: "#e3dd61ff", color: "black", border: "none", padding: "5px 10px", borderRadius: "5px", cursor: "pointer" }}
                                >
                                    🗑️ Obriši
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* MODAL ZA IZMENE I DODAVANJE */}
            {showModal && (
                <div
                    style={{
                        position: "fixed",
                        top: 0,
                        left: 0,
                        width: "100%",
                        height: "100%",
                        backgroundColor: "rgba(0,0,0,0.6)",
                        display: "flex",
                        justifyContent: "center",
                        alignItems: "center",
                    }}
                >
                    <div style={{ backgroundColor: "white", padding: "20px", borderRadius: "10px", width: "400px" }}>
                        <h3>{izabraniGost.idGost ? "Izmeni gosta" : "Dodaj gosta"}</h3>

                        <label>Ime:</label>
                        <input
                            type="text"
                            value={izabraniGost.ime}
                            onChange={(e) => setIzabraniGost({ ...izabraniGost, ime: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>Prezime:</label>
                        <input
                            type="text"
                            value={izabraniGost.prezime}
                            onChange={(e) => setIzabraniGost({ ...izabraniGost, prezime: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>Email:</label>
                        <input
                            type="email"
                            value={izabraniGost.email}
                            onChange={(e) => setIzabraniGost({ ...izabraniGost, email: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>Telefon:</label>
                        <input
                            type="text"
                            value={izabraniGost.telefon}
                            onChange={(e) => setIzabraniGost({ ...izabraniGost, telefon: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>Adresa:</label>
                        <input
                            type="text"
                            value={izabraniGost.adresa}
                            onChange={(e) => setIzabraniGost({ ...izabraniGost, adresa: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>Datum rođenja:</label>
                        <input
                            type="date"
                            value={izabraniGost.datumRodjenja}
                            onChange={(e) => setIzabraniGost({ ...izabraniGost, datumRodjenja: e.target.value })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <label>ID grada:</label>
                        <input
                            type="number"
                            value={izabraniGost.grad ? izabraniGost.grad.idGrad : 1}
                            onChange={(e) => setIzabraniGost({ ...izabraniGost, grad: { idGrad: parseInt(e.target.value) } })}
                            style={{ width: "100%", marginBottom: "10px" }}
                        />

                        <div style={{ display: "flex", justifyContent: "flex-end" }}>
                            <button
                                onClick={() => setShowModal(false)}
                                style={{ marginRight: "10px", backgroundColor: "gray", color: "white", border: "none", borderRadius: "5px", padding: "5px 10px" }}
                            >
                                Otkaži
                            </button>
                            <button
                                onClick={handleSave}
                                style={{ backgroundColor: "green", color: "white", border: "none", borderRadius: "5px", padding: "5px 10px" }}
                            >
                                Sačuvaj
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <Footer />
        </div>
    );
}
